import type React from 'react';

import { cn } from '../utils/cn';

/**
 * A composable empty state container for when no data is available.
 */
function EmptyState({ className, ...props }: React.ComponentProps<'div'>) {
  return (
    <div
      data-slot="empty-state"
      className={cn(
        'flex flex-col items-center justify-center gap-4 py-12 text-center',
        className
      )}
      {...props}
    />
  );
}

/**
 * Icon container for EmptyState. Expects an icon component as children.
 */
function EmptyStateIcon({ className, ...props }: React.ComponentProps<'div'>) {
  return (
    <div
      data-slot="empty-state-icon"
      className={cn('text-muted-foreground', className)}
      {...props}
    />
  );
}

/**
 * Title for EmptyState.
 */
function EmptyStateTitle({
  className,
  ...props
}: React.ComponentProps<'h3'>) {
  return (
    <h3
      data-slot="empty-state-title"
      className={cn('text-lg font-semibold text-foreground', className)}
      {...props}
    />
  );
}

/**
 * Description text for EmptyState.
 */
function EmptyStateDescription({
  className,
  ...props
}: React.ComponentProps<'p'>) {
  return (
    <p
      data-slot="empty-state-description"
      className={cn('text-sm text-muted-foreground max-w-sm', className)}
      {...props}
    />
  );
}

/**
 * Action container for EmptyState. Expects a Button or similar action as children.
 */
function EmptyStateAction({
  className,
  ...props
}: React.ComponentProps<'div'>) {
  return (
    <div
      data-slot="empty-state-action"
      className={cn(className)}
      {...props}
    />
  );
}

export {
  EmptyState,
  EmptyStateIcon,
  EmptyStateTitle,
  EmptyStateDescription,
  EmptyStateAction,
};
